1	import { isActor } from "@fedify/vocab";
2	import { persistActor } from "@hackerspub/models/actor";
3	import { getPostVisibilityFilter } from "@hackerspub/models/post";
4	import { compileQuery, parseQuery } from "@hackerspub/models/search";
5	import {
6	  FULL_HANDLE_REGEXP,
7	  HANDLE_REGEXP,
8	} from "@hackerspub/models/searchPatterns";
9	import { addPostToTimeline } from "@hackerspub/models/timeline";
10	import { sql } from "drizzle-orm";
11	import { createGraphQLError } from "graphql-yoga";
12	import { builder, type UserContext } from "./builder.ts";
13	import { lookupPostByUrl, parseHttpUrl } from "./lookup.ts";
14	import { Post } from "./post.ts";
15	
16	class EmptySearchQueryError extends Error {
17	  public constructor() {
18	    super("Query cannot be empty");
19	  }
20	}
21	
22	builder.objectType(EmptySearchQueryError, {
23	  name: "EmptySearchQueryError",
24	  fields: (t) => ({
25	    message: t.expose("message", { type: "String" }),
26	  }),
27	});
28	
29	const SearchedObject = builder.simpleObject("SearchedObject", {
30	  fields: (t) => ({
31	    url: t.string(),
32	  }),
33	});
34	
35	async function searchAsUrl(
36	  ctx: UserContext,
37	  query: string,
38	): Promise<{ url: string } | null> {
39	  const parsed = parseHttpUrl(query);
40	  if (parsed == null) return null;
41	
42	  const post = await lookupPostByUrl(ctx, parsed);
43	  if (post == null) return null;
44	
45	  await addPostToTimeline(ctx.db, post);
46	
47	  const actor = await ctx.db.query.actorTable.findFirst({
48	    where: { id: post.actorId },
49	  });
50	  if (actor == null) return null;
51	
52	  let redirectUrl: string;
53	  if (actor.accountId == null) {
54	    redirectUrl = `/${actor.handle}/${post.id}`;
55	  } else if (post.noteSourceId != null) {
56	    redirectUrl = `/@${actor.username}/${post.noteSourceId}`;
57	  } else if (post.articleSourceId != null) {
58	    redirectUrl = post.url ?? post.iri;
59	  } else {
60	    return null;
61	  }
62	
63	  return { url: redirectUrl };
64	}
65	
66	async function searchAsHandle(ctx: UserContext, query: string) {
67	  if (!HANDLE_REGEXP.test(query) && !FULL_HANDLE_REGEXP.test(query)) {
68	    return null;
69	  }
70	
71	  // Check for local handle
72	  const match = HANDLE_REGEXP.exec(query);
73	  if (match) {
74	    const account = await ctx.db.query.accountTable.findFirst({
75	      where: { username: match[1].toLowerCase() },
76	    });
77	    if (account != null) {
78	      return { url: `/@${account.username}` };
79	    }
80	  }
81	
82	  // Check for full handle
83	  const fullMatch = FULL_HANDLE_REGEXP.exec(query);
84	  if (!fullMatch) {
85	    return null;
86	  }
87	
88	  const origin = `https://${fullMatch[2]}`;
89	  if (!URL.canParse(origin)) {
90	    return null;
91	  }
92	  const host = new URL(origin).host;
93	
94	  let actor = await ctx.db.query.actorTable.findFirst({
95	    where: {
96	      username: fullMatch[1],
97	      OR: [
98	        { instanceHost: host },
99	        { handleHost: host },
100	      ],
101	    },
102	  });
103	
104	  if (actor != null) {
105	    const redirectUrl = actor.accountId == null
106	      ? `/${actor.handle}`
107	      : `/@${actor.username}`;
108	    return { url: redirectUrl };
109	  }
110	
111	  // Try to fetch remote actor using federation context
112	  const documentLoader = ctx.account == null
113	    ? ctx.fedCtx.documentLoader
114	    : await ctx.fedCtx.getDocumentLoader({ identifier: ctx.account.id });
115	
116	  let object;
117	  try {
118	    object = await ctx.fedCtx.lookupObject(query, { documentLoader });
119	  } catch {
120	    return null;
121	  }
122	
123	  if (!isActor(object)) {
124	    return null;
125	  }
126	
127	  actor = await persistActor(ctx.fedCtx, object!, {
128	    contextLoader: ctx.fedCtx.contextLoader,
129	    documentLoader,
130	    outbox: false,
131	  });
132	
133	  if (actor == null) {
134	    return null;
135	  }
136	  return { url: `/${actor.handle}` };
137	}
138	
139	builder.queryFields((t) => ({
140	  searchPost: t.connection({
141	    type: Post,
142	    args: {
143	      query: t.arg.string({ required: true }),
144	      languages: t.arg({
145	        type: ["Locale"],
146	        defaultValue: [],
147	      }),
148	    },
149	    async resolve(_, args, ctx) {
150	      if (args.last != null || args.before != null) {
151	        throw createGraphQLError("Backward pagination is not supported");
152	      }
153	      const window = args.first ?? 25;
154	      const until = args.after == null ? undefined : new Date(args.after);
155	      const query = args.query.trim();
156	      if (!query) {
157	        throw createGraphQLError("Query cannot be empty");
158	      }
159	
160	      const parsedQuery = parseQuery(query);
161	      if (!parsedQuery) {
162	        throw createGraphQLError("Invalid search query format");
163	      }
164	
165	      const searchFilter = compileQuery(parsedQuery);
166	      const signedAccount = ctx.account;
167	
168	      const languages = args.languages ?? [];
169	
170	      const posts = await ctx.db.query.postTable.findMany({
171	        where: {
172	          AND: [
173	            searchFilter,
174	            signedAccount
