import { isActor } from "@fedify/vocab";
import { persistActor } from "@hackerspub/models/actor";
import { getPostVisibilityFilter } from "@hackerspub/models/post";
import { compileQuery, parseQuery } from "@hackerspub/models/search";
import {
  FULL_HANDLE_REGEXP,
  HANDLE_REGEXP,
} from "@hackerspub/models/searchPatterns";
import { addPostToTimeline } from "@hackerspub/models/timeline";
import { sql } from "drizzle-orm";
import { createGraphQLError } from "graphql-yoga";
import { builder, type UserContext } from "./builder.ts";
import { lookupPostByUrl, parseHttpUrl } from "./lookup.ts";
import { Post } from "./post.ts";

class EmptySearchQueryError extends Error {
  public constructor() {
    super("Query cannot be empty");
  }
}

builder.objectType(EmptySearchQueryError, {
  name: "EmptySearchQueryError",
  fields: (t) => ({
    message: t.expose("message", { type: "String" }),
  }),
});

const SearchedObject = builder.simpleObject("SearchedObject", {
  fields: (t) => ({
    url: t.string(),
  }),
});

async function searchAsUrl(
  ctx: UserContext,
  query: string,
): Promise<{ url: string } | null> {
  const parsed = parseHttpUrl(query);
  if (parsed == null) return null;

  const post = await lookupPostByUrl(ctx, parsed);
  if (post == null) return null;

  await addPostToTimeline(ctx.db, post);

  const actor = await ctx.db.query.actorTable.findFirst({
    where: { id: post.actorId },
  });
  if (actor == null) return null;

  let redirectUrl: string;
  if (actor.accountId == null) {
    redirectUrl = `/${actor.handle}/${post.id}`;
  } else if (post.noteSourceId != null) {
    redirectUrl = `/@${actor.username}/${post.noteSourceId}`;
  } else if (post.articleSourceId != null) {
    redirectUrl = post.url ?? post.iri;
  } else {
    return null;
  }

  return { url: redirectUrl };
}

async function searchAsHandle(ctx: UserContext, query: string) {
  if (!HANDLE_REGEXP.test(query) && !FULL_HANDLE_REGEXP.test(query)) {
    return null;
  }

  // Check for local handle
  const match = HANDLE_REGEXP.exec(query);
  if (match) {
    const account = await ctx.db.query.accountTable.findFirst({
      where: { username: match[1].toLowerCase() },
    });
    if (account != null) {
      return { url: `/@${account.username}` };
    }
  }

  // Check for full handle
  const fullMatch = FULL_HANDLE_REGEXP.exec(query);
  if (!fullMatch) {
    return null;
  }

  const origin = `https://${fullMatch[2]}`;
  if (!URL.canParse(origin)) {
    return null;
  }
  const host = new URL(origin).host;

  let actor = await ctx.db.query.actorTable.findFirst({
    where: {
      username: fullMatch[1],
      OR: [
        { instanceHost: host },
        { handleHost: host },
      ],
    },
  });

  if (actor != null) {
    const redirectUrl = actor.accountId == null
      ? `/${actor.handle}`
      : `/@${actor.username}`;
    return { url: redirectUrl };
  }

  // Try to fetch remote actor using federation context
  const documentLoader = ctx.account == null
    ? ctx.fedCtx.documentLoader
    : await ctx.fedCtx.getDocumentLoader({ identifier: ctx.account.id });

  let object;
  try {
    object = await ctx.fedCtx.lookupObject(query, { documentLoader });
  } catch {
    return null;
  }

  if (!isActor(object)) {
    return null;
  }

  actor = await persistActor(ctx.fedCtx, object!, {
    contextLoader: ctx.fedCtx.contextLoader,
    documentLoader,
    outbox: false,
  });

  if (actor == null) {
    return null;
  }
  return { url: `/${actor.handle}` };
}

builder.queryFields((t) => ({
  searchPost: t.connection({
    type: Post,
    args: {
      query: t.arg.string({ required: true }),
      languages: t.arg({
        type: ["Locale"],
        defaultValue: [],
      }),
    },
    async resolve(_, args, ctx) {
      if (args.last != null || args.before != null) {
        throw createGraphQLError("Backward pagination is not supported");
      }
      const window = args.first ?? 25;
      const until = args.after == null ? undefined : new Date(args.after);
      const query = args.query.trim();
      if (!query) {
        throw createGraphQLError("Query cannot be empty");
      }

      const parsedQuery = parseQuery(query);
      if (!parsedQuery) {
        throw createGraphQLError("Invalid search query format");
      }

      const searchFilter = compileQuery(parsedQuery);
      const signedAccount = ctx.account;

      const languages = args.languages ?? [];

      const posts = await ctx.db.query.postTable.findMany({
        where: {
          AND: [
            searchFilter,
            signedAccount
              ? getPostVisibilityFilter(signedAccount.actor)
              : { visibility: "public" },
            { sharedPostId: { isNull: true } },
            languages.length < 1
              ? (signedAccount?.hideForeignLanguages &&
                  signedAccount.locales != null
                ? { language: { in: signedAccount.locales } }
                : {})
              : { language: { in: [...languages.map((l) => l.baseName)] } },
            until == null ? {} : { published: { lte: until } },
          ],
        },
        with: {
          actor: {
            with: {
              instance: true,
              followers: {
                where: signedAccount == null
                  ? { RAW: sql`false` }
                  : { followerId: signedAccount.actor.id },
              },
              blockees: {
                where: signedAccount == null
                  ? { RAW: sql`false` }
                  : { blockeeId: signedAccount.actor.id },
              },
              blockers: {
                where: signedAccount == null
                  ? { RAW: sql`false` }
                  : { blockerId: signedAccount.actor.id },
              },
            },
          },
          link: { with: { creator: true } },
          mentions: {
            with: { actor: true },
          },
          media: true,
          shares: {
            where: signedAccount == null
              ? { RAW: sql`false` }
              : { actorId: signedAccount.actor.id },
          },
          reactions: {
            where: signedAccount == null
              ? { RAW: sql`false` }
              : { actorId: signedAccount.actor.id },
          },
          replyTarget: {
            with: {
              actor: {
                with: {
                  instance: true,
                  followers: {
                    where: signedAccount == null
                      ? { RAW: sql`false` }
                      : { followerId: signedAccount.actor.id },
                  },
                  blockees: {
                    where: signedAccount == null
                      ? { RAW: sql`false` }
                      : { blockeeId: signedAccount.actor.id },
                  },
                  blockers: {
                    where: signedAccount == null
                      ? { RAW: sql`false` }
                      : { blockerId: signedAccount.actor.id },
                  },
                },
              },
              link: { with: { creator: true } },
              mentions: {
                with: { actor: true },
              },
              media: true,
            },
          },
          sharedPost: {
            with: {
              actor: {
                with: {
                  instance: true,
                  followers: {
                    where: signedAccount == null
                      ? { RAW: sql`false` }
                      : { followerId: signedAccount.actor.id },
                  },
                  blockees: {
                    where: signedAccount == null
                      ? { RAW: sql`false` }
                      : { blockeeId: signedAccount.actor.id },
                  },
                  blockers: {
                    where: signedAccount == null
                      ? { RAW: sql`false` }
                      : { blockerId: signedAccount.actor.id },
                  },
                },
              },
              link: { with: { creator: true } },
              mentions: {
                with: { actor: true },
              },
              media: true,
              shares: {
                where: signedAccount == null
                  ? { RAW: sql`false` }
                  : { actorId: signedAccount.actor.id },
              },
              reactions: {
                where: signedAccount == null
                  ? { RAW: sql`false` }
                  : { actorId: signedAccount.actor.id },
              },
              replyTarget: {
                with: {
                  actor: {
                    with: {
                      instance: true,
                      followers: {
                        where: signedAccount == null
                          ? { RAW: sql`false` }
                          : { followerId: signedAccount.actor.id },
                      },
                      blockees: {
                        where: signedAccount == null
                          ? { RAW: sql`false` }
                          : { blockeeId: signedAccount.actor.id },
                      },
                      blockers: {
                        where: signedAccount == null
                          ? { RAW: sql`false` }
                          : { blockerId: signedAccount.actor.id },
                      },
                    },
                  },
                  link: { with: { creator: true } },
                  mentions: {
                    with: { actor: true },
                  },
                  media: true,
                },
              },
            },
          },
        },
        orderBy: { published: "desc" },
        limit: window + 1,
      });

      return {
        pageInfo: {
          hasNextPage: posts.length > window,
          hasPreviousPage: false,
          startCursor: posts.length < 2
            ? null
            : posts[1].published.toISOString(),
          endCursor: posts.length < 2
            ? null
            : posts.at(-1)!.published.toISOString(),
        },
        edges: posts.slice(0, window).map((
          post,
          i,
        ) => ({
          node: post,
          cursor: posts[i + 1]?.published?.toISOString() ?? "",
          added: post.published,
        })),
      };
    },
  }),
  searchObject: t.field({
    type: SearchedObject,
    nullable: true,
    errors: {
      types: [EmptySearchQueryError],
    },
    args: {
      query: t.arg.string({ required: true }),
    },
    async resolve(_, args, ctx) {
      const query = args.query.trim();
      if (!query) {
        throw new EmptySearchQueryError();
      }

      const result = await searchAsUrl(ctx, query);

      return result == null ? await searchAsHandle(ctx, query) : result;
    },
  }),
}));

import {
  char,
  choice,
  endOfInput,
  exactly,
  letter,
  lookAhead,
  optionalWhitespace,
  type Parser,
  possibly,
  recursiveParser,
  regex,
  sequenceOf,
  startOfInput,
  str,
  whitespace,
} from "arcsecond";
import { sql } from "drizzle-orm";
import type { RelationsFilter } from "./db.ts";

export type Term =
  | { type: "keyword"; keyword: string }
  | { type: "language"; language: string }
  | { type: "actor"; username: string; host?: string }
  | { type: "hashtag"; hashtag: string };

export type Expr =
  | Term
  | { type: "and"; left: Expr; right: Expr }
  | { type: "or"; left: Expr; right: Expr }
  | { type: "not"; expr: Expr };

export const term: Parser<Term> = choice([
  regex(/^\"(?:\\[\\"]|.)+\"/).map<Term>((s) => ({
    type: "keyword",
    keyword: s.slice(1, -1).replace(/\\([\\"])/g, (m) => m[1]),
  })),
  sequenceOf([
    choice([str("lang:"), str("language:")]),
    exactly<string, 2>(2)(letter),
    possibly(letter),
  ]).map<Term>(([_, [l1, l2], l3]) => ({
    type: "language",
    language: l1 + l2 + (l3 ?? ""),
  })),
  sequenceOf([
    choice([str("author:"), str("from:"), str("actor:")]),
    possibly(char("@")),
    regex(/^[^@ \t\v\r\n()]+/),
    possibly(sequenceOf([
      char("@"),
      regex(/^[^ \t\v\r\n()]+/),
    ])),
  ]).map<Term>(([_, __, username, host]) => ({
    type: "actor",
    username,
    host: host?.[1],
  })),
  regex(/^#[\S]+/).map<Term>((s) => ({
    type: "hashtag" as const,
    hashtag: s.substring(1),
  })),
  regex(/^[^ \t\v\r\n()]+/).map<Term>((s) => ({
    type: "keyword",
    keyword: s,
  })),
]);

const exprWithoutOr: Parser<Expr> = recursiveParser(() =>
  sequenceOf([
    choice([
      sequenceOf<string, Term>([
        char("-"),
        term,
      ]).map<Expr>(([_, t]) => ({ type: "not", expr: t })),
      sequenceOf([
        possibly(char("-")),
        char("("),
        optionalWhitespace,
        expr,
        optionalWhitespace,
        char(")"),
      ]).map<Expr>((
        [neg, _, __, e],
      ) => (neg ? { type: "not", expr: e } : e)),
      term,
    ]),
    possibly(sequenceOf<string, string, Expr>([
      whitespace,
      lookAhead(regex(/^(OR[^ \t\v\r\n]|O[^R]|[^O])/i)),
      exprWithoutOr,
    ])),
  ]).map<Expr>(([a, b]) =>
    b == null ? a : { type: "and", left: a, right: b[2] }
  )
);

export const expr: Parser<Expr> = recursiveParser(() =>
  sequenceOf([
    exprWithoutOr,
    possibly(sequenceOf([
      whitespace,
      regex(/^OR/i),
      whitespace,
      expr,
    ])),
  ]).map<Expr>(([a, b]) => b == null ? a : { type: "or", left: a, right: b[3] })
);

const parser = sequenceOf([
  startOfInput,
  optionalWhitespace,
  expr,
  optionalWhitespace,
  endOfInput,
]).map<Expr>(([_, __, e]) => e);

export function parseQuery(input: string): Expr | undefined {
  const result = parser.run(input);
  if (result.isError) return undefined;
  return result.result;
}

export function compileQuery(
  expr: Expr,
): RelationsFilter<"postTable"> {
  switch (expr.type) {
    case "keyword":
      return { contentHtml: { ilike: `%${expr.keyword}%` } };
    case "language":
      return { language: expr.language };
    case "actor":
      return {
        actor: {
          username: expr.username,
          ...(expr.host == null ? { accountId: { isNotNull: true } } : {
            OR: [
              { instanceHost: expr.host },
              { handleHost: expr.host },
            ],
          }),
        },
      };
    case "hashtag":
      return {
        RAW(t) {
          return sql`${t.tags} ? ${expr.hashtag.toLowerCase()}`;
        },
      };
    case "and":
      return {
        AND: [
          compileQuery(expr.left),
          compileQuery(expr.right),
        ],
      };
    case "or":
      return {
        OR: [
          compileQuery(expr.left),
          compileQuery(expr.right),
        ],
      };
    case "not":
      return { NOT: compileQuery(expr.expr) };
  }
}

