import { graphql } from "relay-runtime";
import {
  Accessor,
  createEffect,
  createSignal,
  For,
  Match,
  on,
  Show,
  Switch,
} from "solid-js";
import { createPaginationFragment } from "solid-relay";
import { PostCard } from "~/components/PostCard.tsx";
import { useLingui } from "~/lib/i18n/macro.d.ts";
import type { SearchResults_posts$key } from "./__generated__/SearchResults_posts.graphql.ts";

export interface SearchResultsProps {
  query: Accessor<string>;
  $posts: Accessor<SearchResults_posts$key>;
}

export function SearchResults(props: SearchResultsProps) {
  const { t } = useLingui();
  const posts = createPaginationFragment(
    graphql`
      fragment SearchResults_posts on Query 
        @refetchable(queryName: "SearchResultsQuery")
        @argumentDefinitions(
          cursor: { type: "String" }
          count: { type: "Int", defaultValue: 25 }
          query: { type: "String!" }
          locale: { type: "Locale" }
          languages: { type: "[Locale!]" }
        )
      {
        __id
        searchPost(
          query: $query,
          languages: $languages,
          after: $cursor,
          first: $count,
        )
          @connection(key: "SearchResults__searchPost")
        {
          edges {
            __id
            node {
              ...PostCard_post @arguments(locale: $locale)
            }
          }
          pageInfo {
            hasNextPage
          }
        }
      }
    `,
    () => props.$posts(),
  );
  const [loadingState, setLoadingState] = createSignal<
    "loaded" | "loading" | "errored"
  >("loaded");

  function onLoadMore() {
    setLoadingState("loading");
    posts.loadNext(25, {
      onComplete(error) {
        setLoadingState(error == null ? "loaded" : "errored");
      },
    });
  }
  createEffect(on(props.query, (query) => {
    posts.refetch({
      query,
    });
  }, {
    defer: true,
  }));

  return (
    <div class="border rounded-xl *:first:rounded-t-xl *:last:rounded-b-xl my-4">

